using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly string _tempDir;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;

        public CoursesControllerTests()
        {
            _tempDir = Path.Combine(Path.GetTempPath(), "CoursesTest_" + Guid.NewGuid().ToString("N"));
            Directory.CreateDirectory(_tempDir);
            _envMock = new Mock<IWebHostEnvironment>();
            _envMock.Setup(e => e.WebRootPath).Returns(_tempDir);
            _envMock.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _loggerMock = new Mock<ILogger<CoursesController>>();
        }

        public void Dispose()
        {
            if (Directory.Exists(_tempDir))
            {
                try { Directory.Delete(_tempDir, true); } catch { }
            }
        }

        private CoursesController CreateController(SchoolContext context)
        {
            return new CoursesController(context, _envMock.Object, _loggerMock.Object);
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var controller = CreateController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Course>>(result!.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            var controller = CreateController(context);

            var result = controller.Details(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = CreateController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var controller = CreateController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result!.Model);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 9999,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = controller.Create(course, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(1, context.Courses.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9999, Credits = 3 };

            var result = controller.Create(course, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 8888,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var file = CreateMockFile("test.jpg", 1024);

            var result = controller.Create(course, file) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.StartsWith("/Uploads/TeachingMaterials/", context.Courses.First().TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsModelError()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            var controller = CreateController(context);
            var course = new Course
            {
                CourseID = 7777,
                Title = "Bad File Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var file = CreateMockFile("malware.exe", 1024);

            var result = controller.Create(course, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsModelError()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
