            var result = controller.Edit(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = CreateController(context);

            var result = controller.Edit(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestHelper.CreateContext();
            var controller = CreateController(context);

            var result = controller.Edit(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var controller = CreateController(context);

            var updatedCourse = new Course
            {
                CourseID = course.CourseID,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = course.DepartmentID
            };

            var result = controller.Edit(updatedCourse, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var controller = CreateController(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Credits = 3 };

            var result = controller.Edit(course, null!) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_WithValidImage_SavesNewFile()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var controller = CreateController(context);
            var updatedCourse = new Course
            {
                CourseID = course.CourseID,
                Title = "Updated",
                Credits = 3,
                DepartmentID = course.DepartmentID
            };
            var file = CreateMockFile("new.png", 2048);

            var result = controller.Edit(updatedCourse, file) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_Post_WithInvalidImageExtension_ReturnsModelError()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var controller = CreateController(context);
            var updatedCourse = new Course
            {
                CourseID = course.CourseID,
                Title = "Updated",
                Credits = 3,
                DepartmentID = course.DepartmentID
            };
            var file = CreateMockFile("bad.txt", 1024);

            var result = controller.Edit(updatedCourse, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Post_FileTooLarge_ReturnsModelError()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var controller = CreateController(context);
            var updatedCourse = new Course
            {
                CourseID = course.CourseID,
                Title = "Updated",
                Credits = 3,
                DepartmentID = course.DepartmentID
            };
            var file = CreateMockFile("huge.jpg", 6 * 1024 * 1024);

            var result = controller.Edit(updatedCourse, file) as ViewResult;

            Assert.NotNull(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            var controller = CreateController(context);

            var result = controller.Delete(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result!.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = CreateController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            var controller = CreateController(context);

            var result = controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(1, context.Courses.Count());
        }

        [Fact]
        public void DeleteConfirmed_CourseWithImage_DeletesImageFile()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var course = context.Courses.First();
            // Create an image file
            var uploadsDir = Path.Combine(_tempDir, "Uploads", "TeachingMaterials");
            Directory.CreateDirectory(uploadsDir);
            var imgPath = Path.Combine(uploadsDir, "test.jpg");
            File.WriteAllText(imgPath, "fake image");
            course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test.jpg";
            context.SaveChanges();
            var controller = CreateController(context);

            var result = controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.False(File.Exists(imgPath));
        }

        private static IFormFile CreateMockFile(string fileName, long size)
        {
            var content = new byte[Math.Min(size, 1024)];
            var stream = new MemoryStream(content);
            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(size);
            fileMock.Setup(f => f.OpenReadStream()).Returns(stream);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(s => stream.CopyTo(s));
            return fileMock.Object;
        }
    }
}

