using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests
    {
        [Fact]
        public void Index_NoSelection_ReturnsViewWithInstructors()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result!.Model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            // Add a course assignment
            var instructor = context.Instructors.First();
            var course = context.Courses.First();
            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            });
            context.SaveChanges();
            // Re-query to get fresh data
            var controller = new InstructorsController(context);

            var result = controller.Index(instructor.ID, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result!.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedInstructors(context);
            var instructor = context.Instructors.First();
            var controller = new InstructorsController(context);

            var result = controller.Details(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            using var context = TestHelper.CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Details(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var controller = new InstructorsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Create_Post_ValidInstructor_NoSelectedCourses_RedirectsToIndex()
        {
            using var context = TestHelper.CreateContext();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null!) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(1, context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var courseIds = context.Courses.Select(c => c.CourseID.ToString()).ToArray();
            var controller = new InstructorsController(context);
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Teacher",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, courseIds) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            var savedInstructor = context.Instructors
                .Where(i => i.LastName == "Teacher")
                .First();
            var assignments = context.CourseAssignments
                .Where(ca => ca.InstructorID == savedInstructor.ID)
                .ToList();
            Assert.Equal(courseIds.Length, assignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var controller = new InstructorsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = controller.Create(instructor, null!) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithInstructor()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            var instructor = context.Instructors.First();
            // Ensure CourseAssignments is initialized
            instructor.CourseAssignments ??= new List<CourseAssignment>();
            context.SaveChanges();
            var controller = new InstructorsController(context);

            var result = controller.Edit(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal(instructor.ID, model.ID);
            Assert.NotNull(controller.ViewBag.Courses);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedInstructors(context);
            var instructor = context.Instructors.First();
            var controller = new InstructorsController(context);

            var result = controller.Delete(instructor.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Instructor>(result!.Model);
            Assert.Equal(instructor.ID, model.ID);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestHelper.CreateContext();
            var controller = new InstructorsController(context);

            var result = controller.Delete(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedInstructors(context);
            var instructor = context.Instructors.First();
            // Set up OfficeAssignment
            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Office 101"
            });
            context.SaveChanges();
            var controller = new InstructorsController(context);

            var result = controller.DeleteConfirmed(instructor.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(1, context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var instructor = context.Instructors.First();
            var dept = context.Departments.First(d => d.InstructorID == instructor.ID);
            var controller = new InstructorsController(context);

            controller.DeleteConfirmed(instructor.ID);

            var updatedDept = context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept!.InstructorID);
        }
    }
}

