using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    public class HomeControllerTests
    {
        [Fact]
        public void Index_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void About_ReturnsViewWithEnrollmentGroups()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedStudents(context);
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result!.Model);
            Assert.True(model.Count > 0);
        }

        [Fact]
        public void About_EmptyDb_ReturnsEmptyList()
        {
            using var context = TestHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result!.Model);
            Assert.Empty(model);
        }

        [Fact]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            using var context = TestHelper.CreateContext();
            // Add students with same enrollment date
            var sameDate = DateTime.Parse("2020-09-01");
            context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = sameDate },
                new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = sameDate },
                new Student { FirstMidName = "C", LastName = "C", EnrollmentDate = DateTime.Parse("2021-09-01") }
            );
            context.SaveChanges();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<EnrollmentDateGroup>>(result!.Model);
            Assert.Equal(2, model.Count);
            var group2020 = model.First(g => g.EnrollmentDate == sameDate);
            Assert.Equal(2, group2020.StudentCount);
        }

        [Fact]
        public void Contact_ReturnsViewWithMessage()
        {
            using var context = TestHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Contact() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("Your contact page.", controller.ViewBag.Message);
        }

        [Fact]
        public void Error_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Error() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Unauthorized_ReturnsViewWithMessage()
        {
            using var context = TestHelper.CreateContext();
            var controller = new HomeController(context);

            var result = controller.Unauthorized() as ViewResult;

            Assert.NotNull(result);
            Assert.Equal("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

