using System;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests
    {
        [Fact]
        public void CanCreateInMemoryDatabase()
        {
            using var context = TestHelper.CreateContext();

            Assert.NotNull(context);
            Assert.NotNull(context.Students);
            Assert.NotNull(context.Courses);
            Assert.NotNull(context.Departments);
            Assert.NotNull(context.Instructors);
            Assert.NotNull(context.Enrollments);
            Assert.NotNull(context.CourseAssignments);
            Assert.NotNull(context.OfficeAssignments);
            Assert.NotNull(context.Notifications);
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            using var context = TestHelper.CreateContext();
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            context.Students.Add(student);
            context.SaveChanges();

            var retrieved = context.Students.First();
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            using var context = TestHelper.CreateContext();
            var instructor = new Instructor
            {
                FirstMidName = "John",
                LastName = "Doe",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
            };

            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors.First();
            Assert.Equal("John", retrieved.FirstMidName);
            Assert.Equal("Doe", retrieved.LastName);
        }

        [Fact]
        public void CanAddCourseWithDepartment()
        {
            using var context = TestHelper.CreateContext();
            var dept = new Department
            {
                Name = "Science",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1001,
                Title = "Physics",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var retrieved = context.Courses.Include(c => c.Department).First();
            Assert.Equal("Physics", retrieved.Title);
            Assert.NotNull(retrieved.Department);
            Assert.Equal("Science", retrieved.Department.Name);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);
            TestHelper.SeedStudents(context);

            var student = context.Students.First();
            var course = context.Courses.First();
            context.Enrollments.Add(new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            });
            context.SaveChanges();

            var enrollment = context.Enrollments.First();
            Assert.Equal(Grade.A, enrollment.Grade);
            Assert.Equal(student.ID, enrollment.StudentID);
            Assert.Equal(course.CourseID, enrollment.CourseID);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedCourses(context);

            var instructor = context.Instructors.First();
            var course = context.Courses.First();
            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            });
            context.SaveChanges();

            var assignment = context.CourseAssignments.First();
            Assert.Equal(instructor.ID, assignment.InstructorID);
            Assert.Equal(course.CourseID, assignment.CourseID);
        }

        [Fact]
        public void OfficeAssignment_LinkedToInstructor()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedInstructors(context);
            var instructor = context.Instructors.First();

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            });
            context.SaveChanges();

            var office = context.OfficeAssignments.First();
            Assert.Equal("Room 101", office.Location);
            Assert.Equal(instructor.ID, office.InstructorID);
        }

        [Fact]
        public void CanAddNotification()
        {
            using var context = TestHelper.CreateContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "Test",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.First();
            Assert.Equal("Student", retrieved.EntityType);
            Assert.Equal("Test notification", retrieved.Message);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                FirstMidName = "Jane",
                LastName = "Doe",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            Assert.IsAssignableFrom<Person>(student);
            Assert.Equal("Doe, Jane", student.FullName);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                FirstMidName = "John",
                LastName = "Smith",
                HireDate = DateTime.Parse("2020-01-01")
            };

            Assert.IsAssignableFrom<Person>(instructor);
            Assert.Equal("Smith, John", instructor.FullName);
        }

        [Fact]
        public void Department_WithAdministrator()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);

            var dept = context.Departments.Include(d => d.Administrator).First(d => d.InstructorID != null);

            Assert.NotNull(dept.Administrator);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsDatabase()
        {
            using var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Count() > 0);
            Assert.True(context.Instructors.Count() > 0);
            Assert.True(context.Departments.Count() > 0);
            Assert.True(context.Courses.Count() > 0);
            Assert.True(context.Enrollments.Count() > 0);
            Assert.True(context.CourseAssignments.Count() > 0);
            Assert.True(context.OfficeAssignments.Count() > 0);
        }

        [Fact]
        public void Initialize_DoesNotDuplicateOnSecondCall()
        {
            using var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);
            var studentCount = context.Students.Count();

            DbInitializer.Initialize(context);
            Assert.Equal(studentCount, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsCorrectStudentCount()
        {
            using var context = TestHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsCorrectInstructorCount()
        {
            using var context = TestHelper.CreateContext();
            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
