using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var controller = new DepartmentsController(context);

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result!.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            var controller = new DepartmentsController(context);

            var result = controller.Details(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result!.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            using var context = TestHelper.CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Details(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedInstructors(context);
            var controller = new DepartmentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedInstructors(context);
            var controller = new DepartmentsController(context);
            var dept = new Department
            {
                Name = "Science",
                Budget = 250000,
                StartDate = DateTime.Parse("2023-09-01")
            };

            var result = controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(1, context.Departments.Count());
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedInstructors(context);
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                Budget = 100000,
                StartDate = DateTime.Parse("2023-09-01")
            };

            var result = controller.Create(dept) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(controller.ViewBag.InstructorID);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(id: dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result!.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(id: null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestHelper.CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Edit(id: 9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var controller = new DepartmentsController(context);

            var updatedDept = new Department
            {
                DepartmentID = dept.DepartmentID,
                Name = "Updated English",
                Budget = 400000,
                StartDate = dept.StartDate,
                InstructorID = dept.InstructorID
            };

            var result = controller.Edit(department: updatedDept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var controller = new DepartmentsController(context);
            controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                DepartmentID = 1,
                Budget = 100000,
                StartDate = DateTime.Parse("2023-09-01")
            };

            var result = controller.Edit(department: dept) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result!.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            using var context = TestHelper.CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.NotNull(result);
            Assert.Equal(400, result!.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            using var context = TestHelper.CreateContext();
            var controller = new DepartmentsController(context);

            var result = controller.Delete(9999) as NotFoundResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void DeleteConfirmed_ValidId_RemovesDepartmentAndRedirects()
        {
            using var context = TestHelper.CreateContext();
            TestHelper.SeedDepartments(context);
            var dept = context.Departments.First();
            var controller = new DepartmentsController(context);

            var result = controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result!.ActionName);
            Assert.Equal(1, context.Departments.Count());
        }
    }
}

